const APP_B64="";
const HTML_B64="";
function dec(b){return new TextDecoder().decode(Uint8Array.from(atob(b),function(c){return c.charCodeAt(0)}));}
export default {
  async fetch(req, env) {
    const url = new URL(req.url);
    if (url.pathname === "/app.js") {
      return new Response(dec(APP_B64), { headers: { "content-type":"application/javascript;charset=utf-8", "cache-control":"no-store" } });
    }
    if (url.pathname === "/beacon" && req.method === "POST") {
      const cors = { "content-type":"application/json", "access-control-allow-origin":"*" };
      if (!env || !env.TELEMETRY) return new Response(JSON.stringify({ok:false,err:"no kv binding"}), { status:200, headers: cors });
      let body=""; try { body = await req.text(); } catch(e) {}
      const key = "beacon:" + Date.now() + ":" + Math.random().toString(36).slice(2,8);
      try { await env.TELEMETRY.put(key, body, { expirationTtl: 2592000 }); }
      catch(e) { return new Response(JSON.stringify({ok:false,err:String(e)}), { status:200, headers: cors }); }
      return new Response(JSON.stringify({ok:true,key:key}), { status:200, headers: cors });
    }
    const key = url.searchParams.get("key") || (env && env.TILES_KEY) || "AIzaSyDsv6pVM0beDl0xaqNWmVkyBiUuzxRDr5c";
    return new Response(dec(HTML_B64).replace(/__TILES_KEY__/g, key), { headers: { "content-type":"text/html;charset=utf-8", "cache-control":"no-store" } });
  }
};
